', headers: {…}, status: 404, statusText: null} si le doy al boton personalizado de refrescar que llama a la funcion loadCalendarEvents() entonces si se cargan los eventos este es mi codigo: calendarGoogle.php Aqui esta el calendario <script> const HomeUrl = '<?php echo site_url('home'); ?>'; let calendar; let calendarEl = document.getElementById('calendar'); document.addEventListener('DOMContentLoaded', function() { calendar = new FullCalendar.Calendar(calendarEl, { initialView: 'dayGridMonth', headerToolbar: { left: 'prev,next today myCustomButton logout', center: 'title', right: 'dayGridMonth,timeGridWeek,timeGridDay' }, events: async function(fetchInfo, successCallback, failureCallback) { try { const response = await gapi.client.calendar.events.list({ 'calendarId': 'primary', 'timeMin': fetchInfo.startStr, 'timeMax': fetchInfo.endStr, 'showDeleted': false, 'singleEvents': true, 'maxResults': 100, 'orderBy': 'startTime' }); const events = response.result.items.map(event => { return { title: event.summary, start: event.start.dateTime || event.start.date, end: event.end.dateTime || event.end.date }; }); successCallback(events); } catch (error) { console.error('Error fetching events:', error); failureCallback(error); } }, customButtons: { myCustomButton: { text: 'Refrescar', click: function() { Swal.fire({ title: 'Actualizando calendario...', allowOutsideClick: false, didOpen: () => { Swal.showLoading(); loadCalendarEvents(); }, }); }, }, logout: { text: 'Cerrar Sesión', click: function() { cierre(); } } }, buttonText: { today: 'Hoy', month: 'Mes', week: 'Semana', day: 'Día', list: 'Lista' }, locale: 'es', firstDay: 1, dayMaxEvents: true, eventClick: function(info) { const event = info.event; const title = event.title; const start = event.start; const end = event.end; const allDay = event.allDay; const description = event.extendedProps.description || '--'; const alert = event.extendedProps.alert || ''; const task = event.extendedProps.task || ''; let startFormatted, endFormatted; if (allDay) { startFormatted = moment(start).format('Do MMM, YYYY'); endFormatted = end ? moment(end).format('Do MMM, YYYY') : 'Sin fecha de fin'; } else { startFormatted = moment(start).format('Do MMM, YYYY - h:mm a'); endFormatted = end ? moment(end).format('Do MMM, YYYY - h:mm a') : 'Sin fecha de fin'; } // Rellenar los datos en el modal document.querySelector('[data-kt-calendar="event_name"]').textContent = title; document.querySelector('[data-kt-calendar="all_day"]').textContent = allDay ? 'Todo el día' : ''; document.querySelector('[data-kt-calendar="event_start_date"]').textContent = startFormatted; document.querySelector('[data-kt-calendar="event_end_date"]').textContent = endFormatted; document.querySelector('[data-kt-calendar="event_description"]').textContent = description; document.querySelector('[data-kt-calendar="event_alert"]').textContent = alert; document.querySelector('[data-kt-calendar="event_task"]').textContent = task; // Mostrar el modal de Bootstrap const modal = new bootstrap.Modal(document.getElementById('kt_modal_view_event')); modal.show(); } }); calendar.render(); ensureGapiInitialized().then(loadCalendarEvents).catch(handleError); }); /* function gapiLoaded() { gapi.load('client', initializeGapiClient); } async function initializeGapiClient() { try { await gapi.client.init({ apiKey: "APIKEY", discoveryDocs: ["https://www.googleapis.com/discovery/v1/apis/calendar/v3/rest"], }); gapiInited = true; // Load the calendar events after the client is initialized if (gisInited) { loadCalendarEvents(); } } catch (error) { console.error('Error al inicializar gapi client:', error); } } function gisLoaded() { try { tokenClient = google.accounts.oauth2.initTokenClient({ client_id: "CLIENTID", scope: "https://www.googleapis.com/auth/calendar.readonly", callback: '', // defined later }); gisInited = true; // Load the calendar events after the client is initialized if (gapiInited) { loadCalendarEvents(); } } catch (error) { console.error('Error: Configuración de Google no cargada correctamente.', error); } } */ async function ensureGapiInitialized() { return new Promise((resolve, reject) => { if (typeof gapi !== 'undefined' && gapiInited && gisInited) { resolve(); } else { const checkInterval = setInterval(() => { if (typeof gapi !== 'undefined' && gapiInited && gisInited) { clearInterval(checkInterval); resolve(); } }, 100); setTimeout(() => { clearInterval(checkInterval); reject(new Error('Google Calendar API no está inicializada.')); }, 5000); // Timeout after 5 seconds } }); } function loadCalendarEvents() { tokenClient.callback = async (resp) => { if (resp.error !== undefined) { throw (resp); } const userInfo = await gapi.client.oauth2.userinfo.get(); document.getElementById('accountName').innerText = userInfo.result.email; calendar.refetchEvents(); }; if (gapi.client.getToken() === null) { tokenClient.requestAccessToken({ prompt: 'consent', login_hint: 'user@example.com' }); } else { tokenClient.requestAccessToken({ prompt: '' }); } } function handleError(error) { console.error('Error:', error); Swal.fire({ icon: 'error', title: 'Error', text: 'Ocurrió un error. Por favor, inténtalo de nuevo más tarde.', }); } // CIERRE SESION async function cierre() { console.log('Cerrando sesión Google...'); Swal.fire({ title: 'Cerrando sesión...', allowOutsideClick: false, didOpen: () => { Swal.showLoading(); }, }); try { const token = gapi.client.getToken().access_token; if (token) { // Revocar el token de acceso await fetch(`https://accounts.google.com/o/oauth2/revoke?token=${token}`, { method: 'POST', headers: { 'Content-Type': 'application/x-www-form-urlencoded' } }); console.log('Token revocado correctamente'); gapi.client.setToken(null); localStorage.removeItem('googleAccessToken'); localStorage.setItem('logoutCompletedG', 'true'); console.log('Sesión Google cerrada correctamente'); Swal.close(); const logoutWindow = window.open(`https://accounts.google.com/Logout?continue=https://appengine.google.com/_ah/logout?continue=${HomeUrl}`, '_blank', 'width=500,height=500'); // Esperar unos segundos para asegurarse de que el cierre de sesión se complete setTimeout(() => { if (logoutWindow) { logoutWindow.close(); } Swal.close(); window.location.href = HomeUrl; }, 3000); } } catch (error) { Swal.close(); Swal.fire({ icon: 'error', title: 'Error al cerrar sesión', text: 'Ocurrió un error al intentar cerrar sesión. Por favor, inténtalo de nuevo más tarde.' }); console.log('Error al cerrar sesión Google', error); } } </script> navbar.php aqui se inicia sesion y el navbar siempre esta presente en todas las paginas <!-- Google API --> <script async defer src="https://apis.google.com/js/api.js" onload="gapiLoaded()"></script> <script async defer src="https://accounts.google.com/gsi/client" onload="gisLoaded()"></script> <script type="text/javascript"> //#region GOOGLE // URL calendario Google const calendarGoogleUrl = '<?php echo site_url('calendarGoogle'); ?>'; let tokenClient; let gapiInited = false; let gisInited = false; // Inicializar el cliente de la API de Google async function initializeGapiClient() { try { await gapi.client.init({ apiKey: "API KEY", discoveryDocs: ["https://www.googleapis.com/discovery/v1/apis/calendar/v3/rest"], }); gapiInited = true; } catch (error) { console.error('Error al inicializar gapi client:', error); } } function gapiLoaded() { gapi.load('client', initializeGapiClient); } function gisLoaded() { try { tokenClient = google.accounts.oauth2.initTokenClient({ client_id: "CLIENT ID", scope: "https://www.googleapis.com/auth/calendar.readonly", callback: '', // defined later redirect_uri: '<?php echo site_url('calendarGoogle'); ?>', }); gisInited = true; } catch (error) { console.error('Error: Configuración de Google no cargada correctamente.', error); } } function mostrarCalendarioGoogle() { if (!gapiInited || !gisInited) { console.error("El cliente API de Google aún no se ha inicializado."); return; } try { handleAuthClick(); } catch (error) { handleError(error); } } function handleAuthClick() { tokenClient.callback = async (resp) => { try { if (resp.error !== undefined) { throw (resp); } //Redirigir a la página del calendario de Google window.location.href = calendarGoogleUrl; } catch (error) { handleError(error); } }; if (gapi.client.getToken() === null) { tokenClient.requestAccessToken({ prompt: 'consent', login_hint: 'user@example.com' }); } else { tokenClient.requestAccessToken({ prompt: '' }); } } //#endregion // BOTONES document.addEventListener('DOMContentLoaded', function() { document.getElementById('botonOutlook').addEventListener('click', function(event) { event.preventDefault(); // Previene el comportamiento por defecto del enlace mostrarCalendarioOutlook(); }); document.getElementById('botonGoogle').addEventListener('click', function(event) { event.preventDefault(); // Previene el comportamiento por defecto del enlace mostrarCalendarioGoogle(); }); }); // ERRORES function handleError(error) { const errorCode = error.errorCode || error.error; if (error.errorCode === "interaction_in_progress") { console.warn('Interaction in progress, waiting for it to complete.'); } else if (error.errorCode === "consent_required" || error.errorCode === "interaction_required") { Swal.fire({ icon: 'error', title: 'Permisos necesarios', text: 'El administrador debe conceder los permisos necesarios para acceder a los calendarios. Contacta al administrador.' }); } else if (error.errorCode === "access_denied") { Swal.fire({ icon: 'error', title: 'Acceso denegado', text: 'No se pudo acceder a los datos solicitados. Verifica los permisos y vuelve a intentarlo.' }); } else if (error.errorCode === "user_cancelled") { Swal.fire({ icon: 'error', title: 'Acción Cancelada', text: 'Ha cancelado el inicio de sesión' }); } else { Swal.fire({ icon: 'error', title: 'Error de autenticación', text: 'Ocurrió un error durante la autenticación. Por favor, inténtalo de nuevo más tarde.' }); console.error('Error durante la autenticación:', error); } } function goToCalendarEvent(event) { localStorage.setItem('event', JSON.stringify(event)); window.location.replace('<?= site_url('calendar') ?>') } </script> Si necesitan cualquier información no duden en pedirla ¡Muchísimas Gracias!

Sincronización en segundo plano: WorkManager vs Foreground Service en Android

Estoy desarrollando una app móvil (Android, Kotlin) que tiene que sincronizar datos críticos en segundo plano y quiero balancear entrega fiable, consumo de batería y seguridad (OAuth2). He probado lanzar coroutines desde un foreground service y también WorkManager con backoff exponencial; ambos tienen pros y contras en Doze/optimización de batería y en concurrencia cuando hay múltiples cambios locales. Fragmento de código mínimo que uso ahora:
CoroutineScope(Dispatchers.IO).launch { syncAll() }
Y en logcat aparece ocasionalmente: java.lang.IllegalStateException: Not allowed to start service Intent { ... }

Mi contexto es parcial (microservicio HTTP con tokens renovables, alta concurrencia de usuarios), pero quiero una recomendación arquitectónica concreta: ¿usar WorkManager (con Retrofit+coroutines y retry policy) o mantener un Foreground Service/socket persistente? ¿Cómo manejaría el refresh del token y la sincronización concurrente sin ANRs, minimizando consumo de batería y respetando políticas de Play/Doze? ¿Algún patrón de implementación seguro y escalable?

Título: Fetch con credentials bloqueado por CORS (entrega mañana)

Estoy desarrollando el frontend en React y tengo entrega mañana, me tiene totalmente bloqueado un problema al enviar el login porque necesito que se guarden cookies. Código mínimo que uso:

fetch('http://api.local/login', {
  method: 'POST',
  credentials: 'include',
  headers: {'Content-Type': 'application/json'},
  body: JSON.stringify({ user, pass })
});

En la consola aparece: Access to fetch at 'http://api.local/login' from origin 'http://localhost:3000' has been blocked by CORS policy: No 'Access-Control-Allow-Origin' header is present on the requested resource.

No puedo tocar el backend ahora mismo y necesito una solución rápida para la entrega. ¿Puedo arreglar esto desde el frontend (proxy en CRA, mode, plugin del navegador, nginx local, etc.) para enviar cookies sin cambiar el servidor? ¿Cuál es la forma más segura/rápida para un entorno de desarrollo y qué limitaciones debo tener en cuenta?

Error al tocar botón en Flutter: setState() called after dispose

Estoy intentando hacer una app móvil en Flutter como principiante y estoy totalmente abrumado: al tocar un botón que lanza una petición HTTP la app crashea con el error "setState() called after dispose". Tengo entrega/preview mañana y esto me bloquea por completo. No sé si es por un Future que sigue activo o por el lifecycle del State. Código reducido que uso en el State:

void _buscar() async {
  final res = await http.get(Uri.parse(url));
  setState(() { datos = jsonDecode(res.body); });
}

@override
void dispose() {
  controller.dispose();
  super.dispose();
}

A veces el error sale al volver atrás rápido. ¿Cómo puedo impedir que setState se llame después de dispose sin reescribir toda la pantalla? ¿Hay una forma sencilla para chequear/ cancelar la petición o proteger el setState para un principiante?

Título: Condición de carrera al decrementar stock en backend (deadline mañana)

Estoy abrumado: tengo un servicio Node.js/Express que procesa pedidos y decreta stock en MongoDB; hay picos de concurrencia y la entrega está bloqueada hasta mañana. A veces llego a stock negativo o envío doble. Mi implementación actual usa una transacción simple:

const session = await db.startSession();
await session.withTransaction(async () => {
  await orders.insertOne(order);
  await inventory.updateOne({ sku }, { $inc: { stock: -1 } });
});

Pero sigue ocurriendo inconsistencia bajo carga. Nivel técnico avanzado: estoy considerando tradeoffs entre rendimiento y consistencia (transacciones distribuidas, locks en Redis, bloqueo optimista con versión y retry). También me preocupa latencia y despliegue en shard/replica set.

Pregunta concreta: ¿Cuál es la estrategia recomendada en producción para evitar estas carreras sin degradar demasiado el throughput? ¿Mejor transacciones Mongo escalables, bloqueo distribuido en Redis o control optimista con retries y compensaciones? Ejemplos prácticos o pasos para aplicar antes del deploy serían muy útiles.

Título: Botones dinámicos no responden al click

Estoy haciendo una lista en el frontend donde voy añadiendo botones con innerHTML, pero los que se crean después de inicializar los listeners no responden al click. Ya comprobé que los botones existen en el DOM. Código mínimo que uso:

const container = document.getElementById('lista');
container.innerHTML += '<button class="item">Nuevo</button>';
const botones = document.querySelectorAll('.item');
botones.forEach(b => b.addEventListener('click', e => console.log('clic')));

Solo los botones que ya estaban al cargar la página imprimen "clic". Los creados más tarde no. ¿Estoy perdiendo algo por usar innerHTML o querySelectorAll? ¿Cuál es la forma más sencilla (mínimos cambios) para que todos los botones —incluso los añadidos dinámicamente— respondan al click? ¡Por favor, necesito esto para seguir avanzando!

Título: Problemas de concurrencia y fugas en app Android con Retrofit+Coroutines

Estoy bastante abrumado: tengo una app Android que usa Retrofit + OkHttp y Kotlin Coroutines para peticiones desde un RecyclerView. Al hacer scroll rápido se lanzan cientos de solicitudes y me encuentro con picos de CPU, consumo de batería y algún OOM intermitente. Fragmento simplificado:

CoroutineScope(Dispatchers.IO).launch {
  val r = api.getItem(id)
  // actualizar UI
}

Error/stack (ejemplo): java.lang.OutOfMemoryError: Failed to allocate a 16384 byte allocation

He probado limitar con un Semaphore, usar Dispatchers.IO.limitedParallelism(8) y un singleton OkHttpClient, pero no sé qué tradeoff elegir: rendimiento vs consumo de batería, concurrencia controlada vs latencia, y seguridad (TLS) al reusar conexiones. ¿Cuál es la estrategia recomendada en producción para limitar/coordinar llamadas de red en móviles (pool de OkHttp, semáforo en coroutines, dispatcher limitado, WorkManager, etc.) y cómo implementarla correctamente en Kotlin sin introducir leaks o ANRs?

Titulo: Conexiones perdidas en API Express con pg Pool, ¿qué estoy haciendo mal?

Estoy desarrollando un microservicio backend en Node/Express que usa pg.Pool para Postgres y llevo un par de días con un problema intermitente: después de unas horas de tráfico empieza a fallar con errores como "timeout acquiring client" o "Error: remaining connection 0". Estoy algo confundido porque el código que uso en las rutas es muy sencillo y no sé si el problema es mío o del pool:

const pool = new Pool({/* config */});
app.get('/user/:id', async (req, res) => {
  const client = await pool.connect();
  const result = await client.query('SELECT * FROM users WHERE id = $1', [req.params.id]);
  res.json(result.rows[0]);
});

No siempre pongo client.release() porque pensé que pool.query() lo maneja; además uso transacciones en otras rutas. Necesito resolver esto pronto para la demo de la próxima semana. ¿Cuál es la mejor práctica para evitar fugas de conexiones con pg.Pool (uso try/finally, pool.query vs client.connect), y cómo debería gestionar correctamente transacciones en rutas async para no agotar el pool?

Título: Me llega undefined el user al redireccionar al Dashboard

Estoy abrumado y con entrega mañana: estoy desarrollando el frontend con React y al hacer login y redireccionar al Dashboard el objeto user me llega undefined y eso me bloquea la entrega. Uso react-router y un setState al recibir la respuesta del backend, pero quizás pierdo props o el estado al navegar. Código mínimo: fetch('/api/login', {...}).then(r=>r.json()).then(data=>{ console.log('user:', data.user); this.setState({ user: data.user }); this.props.history.push('/dashboard'); }) en Dashboard: componentDidMount(){ console.log('dashboard user:', this.props.user); }

No pongo el backend por falta de tiempo. ¿Qué causas comunes hacen que user sea undefined tras push() y cómo lo corrijo rápido? ¿Debo usar Context/Redux/localStorage para persistir el usuario antes de redirigir o hay un error en el flujo de setState/props? Gracias.

Título: Deadlock intermitente en transacciones PostgreSQL bajo alta concurrencia

Contexto: Migré el servicio de pagos a PostgreSQL y con concurrencia alta empiezo a ver deadlocks esporádicos que me están bloqueando para la entrega mañana. Tengo un pool de conexiones grande y transacciones cortas que actualizan balances en distinto orden según la lógica del negocio. Ejemplo simplificado:

BEGIN;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

Error: ERROR: deadlock detected; detail: process 12345 waits for ShareLock on transaction 67890; blocking pid 54321

Sé que hay tradeoffs: forzar orden de locking mejora consistencia pero puede penalizar rendimiento; usar serializable reduce anomalías pero afecta throughput; retry aumenta latencia y complica despliegue. Busco una solución que mantenga alta concurrencia y baja latencia sin sacrificar seguridad transaccional.

Pregunta concreta: ¿Cuál es la estrategia práctica recomendada para evitar estos deadlocks en pagos (ordenar locks, SELECT FOR UPDATE, version column optimistic locking, advisory locks, sharding, o tuning del pool)? Indiquen pros/cons y ejemplos de implementación segura y eficiente.

TypeError al renderizar lista en React antes de entrega

Estoy desarrollando la parte frontend de una app y estoy abrumado: la entrega es mañana y este bug me tiene totalmente bloqueado. No incluyo todo el proyecto porque es grande, uso hooks y fetch para traer datos del backend.

Fragmento relevante:
const [items, setItems] = useState();
useEffect(()=>{ fetch('/api/items').then(r=>r.json()).then(setItems); }, []);
return (<ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>);

En consola veo: TypeError: Cannot read properties of undefined (reading 'map'). Probé useState([]) y también items && items.map(...), pero al hacerlo noto parpadeos en la UI y re-renders extra que me preocupan en producción.

Pregunta concreta: ¿Cuál es la forma más segura y limpia (sin anti-patterns) para manejar la carga asíncrona de esta lista en un componente intermedio y evitar el error y re-renders innecesarios antes de la entrega?

¿Por qué mi input con debounce provoca "Too many re-renders" en React?

Estoy trabajando en un formulario en React (funcionales) y me siento bastante abrumado: quiero debouncear la búsqueda mientras el usuario escribe para no hacer muchas peticiones, pero al intentar hacerlo el componente entra en bucle de renders y salta el error "Too many re-renders. React limits the number of renders to prevent an infinite loop." Contexto incompleto: uso useState, useEffect y un handler que recrea el debounce en cada render.

Fragmento relevante:
const [q, setQ] = useState('');
useEffect(() => {
  const timeout = setTimeout(() => fetchData(q), 300);
  return () => clearTimeout(timeout);
}, [q]);

A veces intento envolver fetchData con debounce de lodash dentro del componente y falla. ¿Cuál es la forma correcta de implementar debounce en este caso evitando renders infinitos y sin perder actualizaciones del estado? ¿Debo usar useRef, useCallback o moverlo fuera del componente? ¿Qué trade-offs hay en rendimiento o en consistencia de datos? Necesito una solución clara para una demo esta semana.

Virtualized list (react-window) dispara re-renders y fugas de memoria al hacer scroll

Estoy construyendo una lista virtualizada con react-window y un infinite scroll que hace fetch cuando llego al final. Uso IntersectionObserver para detectar el “sentinel” y en un useEffect vuelvo a observar cada vez que cambian items. A veces en consola aparece "Maximum update depth exceeded" y el consumo de memoria sube; otras veces se llaman varias peticiones simultáneas y veo items duplicados o saltos de layout.

Fragmento relevante:
const observer = useRef();
useEffect(() => {
  observer.current = new IntersectionObserver(handleIntersect);
  observer.current.observe(sentinelRef.current);
  return () => observer.current.disconnect();
}, [items]);

Estoy confundido sobre si el problema es la dependencia en items, la falta de cancelación de fetches o la interacción con react-window (recalculo de altura). Sé que la virtualización mejora rendimiento, pero aquí me da problemas de concurrencia y arquitectura de estado. ¿Cuál es la causa más probable de estos re-renders/múltiples fetches y qué patrón recomiendan (p. ej. useReducer, AbortController, debounce, gestión centralizada de estado) para evitar race conditions y memory leaks en un infinite scroll virtualizado?

Título: No encuentro por qué mi verificador de sexo marca todo como 'm'

Tengo dos DataFrames: dfNoms con nombres y dfRef con listas de nombres por sexo. Intento crear una columna verificadorDeSexoUnitario que sea 'm' si el nombre está en la lista de hombres, 'f' si está en la lista de mujeres y 'n' si no aparece. Código reducido:

hombres = set(dfRef[dfRef.sexo=='M'].nombre)
# ...similar para mujeres

def verificador(nombre):
    if nombre in hombres:
        return 'm'
    elif nombre in mujeres:
        return 'f'
    else:
        return 'n'

dfNoms['verificadorDeSexoUnitario'] = dfNoms['nombre'].apply(verificador)

El problema: la columna nueva queda toda como 'm'. Estoy frustrado y esto me bloquea: necesito la entrega mañana y no puedo usar .isin(). ¿Qué puede estar haciendo mal? ¿Cómo depuro o refactorizo esto sin bucles y respetando que no use .isin() para obtener resultados correctos y eficientes?

Hydration mismatch en Next.js tras reducir bundle — ¿qué falla?

Hola, estoy optimizando una app React/Next.js para una entrega urgente (esto está bloqueando el despliegue mañana). Reduje el bundle con dynamic imports y client-only components pero ahora tengo errores de hidratación y algunos componentes no muestran el estado inicial. No puedo subir el repo completo, dejo un fragmento mínimo: 

export default function Comp(){
  const [open,setOpen]=useState(false);
  useEffect(()=>{ setOpen(true) },[]);
  return <div>{open ? 'ON' : 'OFF'}</div>
}

En consola: "Warning: Text content did not match. Server: 'OFF' Client: 'ON'". Sospecho tradeoffs entre SSR y rendimiento del bundle, o que el setState en useEffect provoca el desfase; también me preocupa impacto en SEO y seguridad. ¿Cuál es la solución correcta aquí: evitar setState en useEffect, marcar el componente como client-only (dynamic import con ssr:false) o pasar a más CSR? ¿Qué riesgos de rendimiento/SEO/despliegue tiene cada opción y cuál es la opción recomendada para producción?

WorkManager vs ForegroundService para tareas largas en Android

Estoy implementando sincronización periódica en segundo plano para una app móvil (Android/Kotlin). Necesito ejecutar tareas CPU-intensivas y llamadas de red sin bloquear la UI y con control de concurrencia y consumo de batería. Intenté usar CoroutineWorker pero noto corutinas que siguen corriendo tras devolver Result.success():

class SyncWorker(appContext: Context, params: WorkerParameters) : CoroutineWorker(appContext, params) {
  override suspend fun doWork(): Result {
    GlobalScope.launch(Dispatchers.Default) { heavyCompute() } // ejemplo
    return Result.success()
  }
}

En el log aparece: W/WorkManager: Worker returned success but background coroutine still running

